// POLONIUM CreepyDrive / CreepySnail Graph API + Dropbox C2 hunt
let suspect_hosts = dynamic(["graph.microsoft.com","api.dropboxapi.com","content.dropboxapi.com","api.onedrive.com"]);
let legit_callers = dynamic(["onedrive.exe","teams.exe","outlook.exe","winword.exe","excel.exe","powerpnt.exe","onenote.exe","msedge.exe","chrome.exe","firefox.exe","iexplore.exe","olk.exe","skype.exe","backgroundtaskhost.exe","searchapp.exe"]);
let net_signal =
    DeviceNetworkEvents
    | where Timestamp > ago(7d)
    | where RemoteUrl has_any (suspect_hosts) or RemoteIPType == "Public" and tostring(RemoteUrl) matches regex @"(?i)(graph\.microsoft\.com|dropboxapi\.com|onedrive\.com)"
    | where InitiatingProcessFileName !in~ (legit_callers)
    | summarize ConnCount=count(), FirstSeen=min(Timestamp), LastSeen=max(Timestamp), URLs=make_set(RemoteUrl,20) by DeviceId, DeviceName, InitiatingProcessFileName, InitiatingProcessFolderPath, InitiatingProcessAccountName, InitiatingProcessParentFileName;
let proc_signal =
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where ProcessCommandLine has_any ("graph.microsoft.com","api.dropboxapi.com","content.dropboxapi.com","/me/drive/root:/","/me/drive/items/","oauth2/v2.0/token")
      and ProcessCommandLine has_any ("Invoke-RestMethod","Invoke-WebRequest","IWR","IRM","WebClient","HttpClient","curl","Bearer")
    | project DeviceId, DeviceName, ProcCmd=ProcessCommandLine, ProcFile=FileName, Parent=InitiatingProcessFileName, User=AccountName, ProcTime=Timestamp;
net_signal
| join kind=inner proc_signal on DeviceId
| where ProcTime between ((FirstSeen - 10m) .. (LastSeen + 10m))
| extend ThreatActor="POLONIUM (Plaid Rain) — G1005", ImplantFamily="CreepyDrive / CreepySnail"
| project ThreatActor, ImplantFamily, DeviceName, InitiatingProcessFileName, ProcFile, Parent, User, ConnCount, URLs, ProcCmd, FirstSeen, LastSeen
| order by LastSeen desc
